import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F14_負債結構與償債壓力測試.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F14_負債結構與償債壓力測試.md"}'),o={name:"審計報告庫/財務審計/6239_力成/20260617/F14_負債結構與償債壓力測試.md"};function i(n,a,h,s,d,_){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="f14-負債結構與償債壓力測試-財務審計專家報告" tabindex="-1">F14: 負債結構與償債壓力測試 - 財務審計專家報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-財務審計專家報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：負債比41.9%處5年高、長債254億（+50%）；但流動比195%、利息保障34倍、短債0。長期壓力在2027年折舊高峰對利息覆蓋率的侵蝕。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>力成2025年負債總額518.9億（總資產1,231.6億），負債比41.9%。短期借款為0，流動負債237.8億中主要為：應付帳款75.7億、應付工程設備款30.5億、應付薪資22.0億等營運性負債，無須支付利息的短期融資。長債301.2億（扣除一年內到期47.0億後淨長債254.1億），加權平均利率約1.5-1.8%，利息支出僅2.59億。利息保障倍數：EBIT 90.5億/利息2.59億=34.9倍。淨債務/EBITDA：（長債301.2億-現金163.8億）/EBITDA（EBIT+折舊202.8億）=0.68倍，極低槓桿。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="債務結構分析" tabindex="-1">債務結構分析 <a class="header-anchor" href="#債務結構分析" aria-label="Permalink to &quot;債務結構分析&quot;">​</a></h3><p>長債301.2億拆解：擔保銀行借款118.0億（年利率1.275-1.840%，到期115/1-120/8）、無擔保銀行借款183.2億（年利率0.600-1.809%，到期115/1-119/9）。一年內到期47.0億（15.6%），到期結構分散，無集中到期壓力。短期借款為0已持續兩年。流動負債237.8億中真正需要支付利息的僅1.8億（租賃負債流動部分+應付費用中極少利息項目），營運資金完全透過自有現金及供應商融資支應。</p><h3 id="利息覆蓋倍數與高息敏感度" tabindex="-1">利息覆蓋倍數與高息敏感度 <a class="header-anchor" href="#利息覆蓋倍數與高息敏感度" aria-label="Permalink to &quot;利息覆蓋倍數與高息敏感度&quot;">​</a></h3><p>利率敏感度測試：當前加權平均利率約1.5-1.8%。假設利率上升100bps（至2.5-2.8%），長債301.2億新增利息支出3.0億，總利息增至5.6億，稅前淨利降至82.0億（影響-3.4%）。假設利率上升200bps（至3.5-3.8%），新增利息6.0億，總利息8.6億，稅前淨利降至80.0億（影響-6.8%）。力成對利率上升的敏感性極低，主因利率基期低且長債佔營收比可控（40%）。</p><h3 id="財務比率符合度" tabindex="-1">財務比率符合度 <a class="header-anchor" href="#財務比率符合度" aria-label="Permalink to &quot;財務比率符合度&quot;">​</a></h3><p>年報附註揭露長期借款合約規定力成須維持：流動比率、固定比率、負債比、金融負債比、自有資本比、利息保障倍數、有形資產、淨值及負債占有形淨值比等限制。截至2025年底各項均符合規定。2025年因CapEx擴張使負債比從35.0%升至41.9%，仍在銀行合約的容許範圍內。若2026年負債比攀升至45-50%，需關注是否觸及合約上限。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>長債急升且沒有短期緩解</strong>：長債55.5億→254億（+358%），兩年膨脹4.5倍。2026年CapEx若持續超支，負債比可能突破50%，將影響授信評級。</li><li><strong>償債能力指標趨勢惡化</strong>：利息保障倍數從57倍降至34倍、流動比256%→195%、現金比121%→69%，全部趨勢向下。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>目前償債能力仍安全</strong>：利息保障34倍仍高於安全線（5倍），流動比195%充足。長債254億/EBITDA約2.9倍，低於3倍可接受。無擔保銀行借款加可轉債利率低，財務成本可控。</li><li><strong>負債用於成長投資</strong>：長債為FOPLP/HBM/CPO設備購置，非償還舊債或財務操作。新產能量產後營收成長將自然稀釋負債比。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>短期償債壓力測試過關。長期風險在於若2027年新產能利用率未達預期，折舊將壓縮獲利使利息保障倍數持續下降。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (balance_sheet 6239)</li><li>原始數據：FinMind TaiwanStockBalanceSheet</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 8、43-44，資產負債表及借款附註)</li><li>年報數據：2025_Q4_6239_合併.pdf (page 54，財務成本明細)</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const p=e(o,[["render",i]]);export{u as __pageData,p as default};
